#!/bin/bash\n\n################################################################################\n# Script de Compilación - Versión Manager en Termux\n# Versión: 1.0.0\n# Descripción: Compila automáticamente el APK Manager en Termux\n# Plataforma: Termux (Android)\n# Rol: Manager (Permisos Medios)\n################################################################################\n\n# Colores para la salida\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nMAGENTA='\\033[0;35m'\nCYAN='\\033[0;36m'\nORANGE='\\033[0;33m'\nNC='\\033[0m' # No Color\n\n# Emojis\nCHECK=\"✅\"\nERROR=\"❌\"\nWARN=\"⚠️ \"\nINFO=\"ℹ️ \"\nHOURGLASS=\"⏳\"\nGEAR=\"🔧\"\nBUILD=\"🔨\"\nFILE=\"📁\"\nSUCCESS=\"🎉\"\nMANAGER=\"👔\"\n\n# Directorios\nPROJECT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nAPK_DIR=\"$PROJECT_DIR/dist/apks\"\nLOG_FILE=\"$PROJECT_DIR/dist/compile-manager-termux.log\"\nBUILD_DIR=\"$PROJECT_DIR/.expo\"\n\n# Función para imprimir con color\nprint_header() {\n    echo -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\n    echo -e \"${CYAN}$1${NC}\"\n    echo -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}${CHECK} $1${NC}\"\n}\n\nprint_error() {\n    echo -e \"${RED}${ERROR} $1${NC}\"\n}\n\nprint_warning() {\n    echo -e \"${YELLOW}${WARN}$1${NC}\"\n}\n\nprint_info() {\n    echo -e \"${BLUE}${INFO}$1${NC}\"\n}\n\nprint_step() {\n    echo -e \"${MAGENTA}$1${NC}\"\n}\n\nprint_manager() {\n    echo -e \"${ORANGE}${MANAGER} $1${NC}\"\n}\n\n# Función para registrar en log\nlog_message() {\n    echo \"[$(date '+%Y-%m-%d %H:%M:%S')] $1\" >> \"$LOG_FILE\"\n}\n\n# Función para manejar errores\nerror_exit() {\n    print_error \"$1\"\n    log_message \"ERROR: $1\"\n    exit 1\n}\n\n# Banner inicial\nclear\necho -e \"${ORANGE}\"\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║                                                               ║\"\necho \"║    GESTOR DE CRÉDITOS Y COBRANZAS - COMPILACIÓN MANAGER      ║\"\necho \"║                                                               ║\"\necho \"║              Script de Compilación en Termux                  ║\"\necho \"║                                                               ║\"\necho \"║                    Versión 1.0.0-manager                      ║\"\necho \"║                    Rol: Manager (Permisos Medios)             ║\"\necho \"║                                                               ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\necho -e \"${NC}\"\necho \"\"\n\n# Información inicial\nprint_info \"Directorio del proyecto: $PROJECT_DIR\"\nprint_info \"Directorio de APKs: $APK_DIR\"\nprint_manager \"Versión: Manager (👔 Permisos Medios)\"\necho \"\"\n\n# Inicializar log\necho \"═══════════════════════════════════════════════════════════════\" > \"$LOG_FILE\"\necho \"Compilación de APK - Gestor de Créditos (Manager)\" >> \"$LOG_FILE\"\necho \"Fecha: $(date '+%Y-%m-%d %H:%M:%S')\" >> \"$LOG_FILE\"\necho \"Plataforma: Termux (Android)\" >> \"$LOG_FILE\"\necho \"Versión: 1.0.0-manager\" >> \"$LOG_FILE\"\necho \"Rol: Manager\" >> \"$LOG_FILE\"\necho \"═══════════════════════════════════════════════════════════════\" >> \"$LOG_FILE\"\necho \"\" >> \"$LOG_FILE\"\n\nlog_message \"Iniciando compilación de APK Manager\"\n\n# PASO 1: Verificar Termux\nprint_header \"PASO 1: Verificando Termux\"\nif [ ! -d \"$PREFIX\" ]; then\n    error_exit \"Este script debe ejecutarse DENTRO de Termux\"\nfi\nprint_success \"Termux detectado correctamente\"\nlog_message \"Termux verificado\"\necho \"\"\n\n# PASO 2: Verificar Node.js\nprint_header \"PASO 2: Verificando Node.js\"\nif ! command -v node &> /dev/null; then\n    print_warning \"Node.js no está instalado\"\n    print_step \"Instalando Node.js...\"\n    pkg install -y nodejs >> \"$LOG_FILE\" 2>&1\n    if [ $? -ne 0 ]; then\n        error_exit \"Falló la instalación de Node.js\"\n    fi\n    print_success \"Node.js instalado\"\n    log_message \"Node.js instalado correctamente\"\nelse\n    NODE_VERSION=$(node --version)\n    print_success \"Node.js detectado: $NODE_VERSION\"\n    log_message \"Node.js encontrado: $NODE_VERSION\"\nfi\necho \"\"\n\n# PASO 3: Verificar npm\nprint_header \"PASO 3: Verificando npm\"\nif ! command -v npm &> /dev/null; then\n    error_exit \"npm no está disponible\"\nfi\nNPM_VERSION=$(npm --version)\nprint_success \"npm detectado: $NPM_VERSION\"\nlog_message \"npm encontrado: $NPM_VERSION\"\necho \"\"\n\n# PASO 4: Limpiar caché\nprint_header \"PASO 4: Limpiando caché\"\nprint_step \"Limpiando npm cache...\"\nnpm cache clean --force >> \"$LOG_FILE\" 2>&1\nprint_success \"Caché limpiado\"\nlog_message \"Caché de npm limpiado\"\necho \"\"\n\n# PASO 5: Instalar dependencias\nprint_header \"PASO 5: Instalando dependencias del proyecto\"\nprint_step \"Ejecutando: npm install\"\necho \"\"\n\nif npm install >> \"$LOG_FILE\" 2>&1; then\n    print_success \"Dependencias instaladas correctamente\"\n    log_message \"Dependencias instaladas exitosamente\"\nelse\n    print_error \"Falló la instalación de dependencias\"\n    log_message \"ERROR: Falló la instalación de dependencias\"\n    error_exit \"No se pudieron instalar las dependencias\"\nfi\necho \"\"\n\n# PASO 6: Instalar EAS CLI\nprint_header \"PASO 6: Instalando EAS CLI\"\nif ! command -v eas &> /dev/null; then\n    print_warning \"EAS CLI no está instalado\"\n    print_step \"Instalando EAS CLI globalmente...\"\n    npm install -g eas-cli >> \"$LOG_FILE\" 2>&1\n    if [ $? -ne 0 ]; then\n        error_exit \"Falló la instalación de EAS CLI\"\n    fi\n    print_success \"EAS CLI instalado\"\n    log_message \"EAS CLI instalado correctamente\"\nelse\n    EAS_VERSION=$(eas --version)\n    print_success \"EAS CLI detectado: $EAS_VERSION\"\n    log_message \"EAS CLI encontrado: $EAS_VERSION\"\nfi\necho \"\"\n\n# PASO 7: Configurar versión Manager\nprint_header \"PASO 7: Configurando versión Manager\"\nprint_step \"Preparando configuración para Manager...\"\n\nif [ ! -f \"$PROJECT_DIR/app-manager.json\" ]; then\n    error_exit \"Archivo app-manager.json no encontrado\"\nfi\n\n# Hacer backup de app.json original\nif [ -f \"$PROJECT_DIR/app.json\" ]; then\n    cp \"$PROJECT_DIR/app.json\" \"$PROJECT_DIR/app.json.backup\" >> \"$LOG_FILE\" 2>&1\n    print_info \"Backup de app.json creado\"\nfi\n\n# Copiar configuración de Manager\ncp \"$PROJECT_DIR/app-manager.json\" \"$PROJECT_DIR/app.json\" >> \"$LOG_FILE\" 2>&1\nif [ $? -ne 0 ]; then\n    error_exit \"Falló la configuración de Manager\"\nfi\n\nprint_success \"Configuración Manager aplicada\"\nlog_message \"Configuración de Manager preparada\"\necho \"\"\n\n# PASO 8: Prebuild de Expo\nprint_header \"PASO 8: Preparando Expo (Prebuild)\"\nprint_step \"Ejecutando: npx expo prebuild --clean\"\necho \"\"\n\nif npx expo prebuild --clean --platform android >> \"$LOG_FILE\" 2>&1; then\n    print_success \"Prebuild completado\"\n    log_message \"Prebuild de Expo completado\"\nelse\n    print_warning \"Prebuild completado con advertencias\"\n    log_message \"Prebuild completado (con advertencias)\"\nfi\necho \"\"\n\n# PASO 9: Compilar APK\nprint_header \"PASO 9: Compilando APK Manager\"\n\necho -e \"${ORANGE}╔═══════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${ORANGE}║                                                               ║${NC}\"\necho -e \"${ORANGE}║         ${HOURGLASS} COMPILACIÓN EN PROGRESO ${HOURGLASS}                        ║${NC}\"\necho -e \"${ORANGE}║                                                               ║${NC}\"\necho -e \"${ORANGE}║     Esto puede tomar 30-40 minutos...                        ║${NC}\"\necho -e \"${ORANGE}║     Por favor, NO cierres Termux                             ║${NC}\"\necho -e \"${ORANGE}║                                                               ║${NC}\"\necho -e \"${ORANGE}╚═══════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\nprint_step \"Ejecutando: eas build --platform android --local\"\nlog_message \"Iniciando compilación de APK\"\n\nSTART_TIME=$(date +%s)\n\nif eas build --platform android --local >> \"$LOG_FILE\" 2>&1; then\n    END_TIME=$(date +%s)\n    DURATION=$((END_TIME - START_TIME))\n    MINUTES=$((DURATION / 60))\n    SECONDS=$((DURATION % 60))\n    \n    print_success \"APK compilado correctamente\"\n    print_info \"Tiempo de compilación: ${MINUTES}m ${SECONDS}s\"\n    log_message \"APK compilado exitosamente en ${MINUTES}m ${SECONDS}s\"\nelse\n    print_error \"Falló la compilación del APK\"\n    log_message \"ERROR: Falló la compilación del APK\"\n    error_exit \"No se pudo compilar el APK\"\nfi\necho \"\"\n\n# PASO 10: Buscar APK generado\nprint_header \"PASO 10: Localizando APK generado\"\n\nAPK_FILE=$(find \"$PROJECT_DIR\" -name \"*manager*.apk\" -o -name \"*Manager*.apk\" | head -1)\n\nif [ -z \"$APK_FILE\" ]; then\n    # Buscar en android/app/build/outputs/\n    APK_FILE=$(find \"$PROJECT_DIR/android/app/build/outputs\" -name \"*.apk\" 2>/dev/null | head -1)\nfi\n\nif [ -z \"$APK_FILE\" ]; then\n    print_warning \"APK no encontrado en ubicación esperada\"\n    print_info \"Buscando en todo el proyecto...\"\n    APK_FILE=$(find \"$PROJECT_DIR\" -name \"*.apk\" -type f 2>/dev/null | sort -r | head -1)\nfi\n\nif [ -z \"$APK_FILE\" ]; then\n    error_exit \"No se encontró el APK compilado\"\nfi\n\n# Crear directorio de APKs si no existe\nmkdir -p \"$APK_DIR\"\n\n# Copiar APK a directorio de distribución\nAPK_FILENAME=\"gestor-creditos-manager-$(date '+%Y%m%d_%H%M%S').apk\"\ncp \"$APK_FILE\" \"$APK_DIR/$APK_FILENAME\" >> \"$LOG_FILE\" 2>&1\n\nif [ $? -ne 0 ]; then\n    error_exit \"Falló al copiar el APK\"\nfi\n\nAPK_SIZE=$(du -h \"$APK_DIR/$APK_FILENAME\" | cut -f1)\n\nprint_success \"APK encontrado: $APK_FILENAME\"\nprint_info \"Tamaño: $APK_SIZE\"\nprint_info \"Ubicación: $APK_DIR/$APK_FILENAME\"\nlog_message \"APK copiado: $APK_DIR/$APK_FILENAME ($APK_SIZE)\"\necho \"\"\n\n# PASO 11: Restaurar configuración original\nprint_header \"PASO 11: Restaurando configuración original\"\nif [ -f \"$PROJECT_DIR/app.json.backup\" ]; then\n    mv \"$PROJECT_DIR/app.json.backup\" \"$PROJECT_DIR/app.json\" >> \"$LOG_FILE\" 2>&1\n    print_success \"Configuración original restaurada\"\n    log_message \"Configuración original restaurada\"\nfi\necho \"\"\n\n# PASO 12: Resumen final\nprint_header \"RESUMEN FINAL\"\necho \"\"\necho -e \"${ORANGE}╔═══════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${ORANGE}║                                                               ║${NC}\"\necho -e \"${ORANGE}║        ${SUCCESS} COMPILACIÓN COMPLETADA EXITOSAMENTE ${SUCCESS}                ║${NC}\"\necho -e \"${ORANGE}║                                                               ║${NC}\"\necho -e \"${ORANGE}╚═══════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\necho -e \"${CYAN}Información de la Compilación:${NC}\"\necho -e \"  Aplicación: Gestor de Créditos - Manager\"\necho -e \"  Versión: 1.0.0-manager\"\necho -e \"  Package: com.gestorcreditos.manager\"\necho -e \"  Rol: Manager (👔 Permisos Medios)\"\necho -e \"  Tamaño: $APK_SIZE\"\necho -e \"  Ubicación: $APK_DIR/$APK_FILENAME\"\necho -e \"  Fecha: $(date '+%Y-%m-%d %H:%M:%S')\"\necho \"\"\n\necho -e \"${CYAN}Características del Manager:${NC}\"\necho -e \"  ✅ Ver deudores\"\necho -e \"  ✅ Editar pagos\"\necho -e \"  ✅ Ver reportes\"\necho -e \"  ✅ Gestionar notificaciones\"\necho -e \"  ✅ Exportar datos\"\necho -e \"  ❌ Crear/eliminar deudores (Admin only)\"\necho -e \"  ❌ Gestionar usuarios (Admin only)\"\necho \"\"\n\necho -e \"${CYAN}Próximos Pasos:${NC}\"\necho -e \"  1. Instalar APK: bash install-apk-termux.sh\"\necho -e \"  2. Abre la aplicación en tu dispositivo\"\necho -e \"  3. Toca 'Registrarse'\"\necho -e \"  4. Crea tu cuenta de Manager\"\necho -e \"  5. ¡Comienza a usar!\"\necho \"\"\n\necho -e \"${GREEN}${CHECK} ¡Compilación completada! El APK está listo para instalar.${NC}\"\necho \"\"\n\nlog_message \"Compilación finalizada exitosamente\"\nlog_message \"═══════════════════════════════════════════════════════════════\"\n\necho -e \"${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}\"\necho \"\"\n\nprint_success \"¡Compilación completada!\"\necho \"\"\n
